//! `truefix-core` — FIX message model, field types, and the SOH wire codec.
//!
//! Provides [`Field`], [`FieldMap`], [`Group`], and [`Message`] (header/body/trailer),
//! plus [`encode`]/[`decode`] that compute and verify BodyLength (tag 9) and CheckSum
//! (tag 10). All parsing returns typed errors and never panics (Constitution Principle I).
//!
//! Repeating-group *structure* is modelled here; dictionary-driven group *parsing* from a
//! flat wire message arrives with `truefix-dict` (Stage S4). At this layer, decoding yields
//! flat ordered fields, which still round-trips byte-for-byte.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

pub mod codec;
pub mod cracker;
pub mod error;
pub mod factory;
pub mod field;
pub mod field_map;
pub mod group;
pub mod message;
pub mod tags;

pub use codec::{decode, encode};
pub use cracker::MessageCracker;
pub use error::{DecodeError, FieldError};
pub use factory::MessageFactory;
pub use field::Field;
pub use field_map::FieldMap;
pub use group::Group;
pub use message::Message;
pub use tags::SOH;

//! Typed errors for the core layer. No code path panics (Constitution Principle I).

use thiserror::Error;

/// Error converting a field's raw value to a typed Rust value.
#[derive(Debug, Clone, PartialEq, Eq, Error)]
pub enum FieldError {
    /// The raw value is not valid UTF-8.
    #[error("field {tag}: value is not valid UTF-8")]
    NotUtf8 {
        /// The field tag.
        tag: u32,
    },
    /// The value is not a valid integer.
    #[error("field {tag}: expected an integer, got {value:?}")]
    NotInt {
        /// The field tag.
        tag: u32,
        /// The offending value.
        value: String,
    },
    /// The value is not a valid decimal.
    #[error("field {tag}: expected a decimal, got {value:?}")]
    NotDecimal {
        /// The field tag.
        tag: u32,
        /// The offending value.
        value: String,
    },
    /// The value is not a single character.
    #[error("field {tag}: expected a single character, got {value:?}")]
    NotChar {
        /// The field tag.
        tag: u32,
        /// The offending value.
        value: String,
    },
    /// The value is not a boolean (`Y`/`N`).
    #[error("field {tag}: expected 'Y' or 'N', got {value:?}")]
    NotBool {
        /// The field tag.
        tag: u32,
        /// The offending value.
        value: String,
    },
    /// The value is not a valid UTC timestamp.
    #[error("field {tag}: invalid UTC timestamp {value:?}")]
    NotTimestamp {
        /// The field tag.
        tag: u32,
        /// The offending value.
        value: String,
    },
}

/// Error decoding raw bytes into a [`Message`](crate::Message).
#[derive(Debug, Clone, PartialEq, Eq, Error)]
pub enum DecodeError {
    /// The input was empty.
    #[error("empty input")]
    Empty,
    /// The message does not start with BeginString (tag 8).
    #[error("message does not begin with BeginString (tag 8)")]
    MissingBeginString,
    /// BodyLength (tag 9) is missing or not a valid number.
    #[error("missing or invalid BodyLength (tag 9)")]
    InvalidBodyLength,
    /// The declared BodyLength does not match the actual body size.
    #[error("BodyLength mismatch: declared {declared}, actual {actual}")]
    BodyLengthMismatch {
        /// Value declared in tag 9.
        declared: usize,
        /// Actual measured body length.
        actual: usize,
    },
    /// CheckSum (tag 10) is missing or not a valid number.
    #[error("missing or invalid CheckSum (tag 10)")]
    MissingChecksum,
    /// The declared CheckSum does not match the computed one.
    #[error("CheckSum mismatch: declared {declared:03}, computed {computed:03}")]
    ChecksumMismatch {
        /// Value declared in tag 10.
        declared: u32,
        /// Locally computed checksum.
        computed: u32,
    },
    /// A field could not be parsed.
    #[error("garbled field near byte {offset}: {reason}")]
    GarbledField {
        /// Byte offset where the problem was detected.
        offset: usize,
        /// Human-readable reason.
        reason: &'static str,
    },
    /// The input ended before a field was complete.
    #[error("truncated input near byte {offset}")]
    Truncated {
        /// Byte offset where truncation was detected.
        offset: usize,
    },
    /// A tag number was not a valid positive integer.
    #[error("invalid tag number near byte {offset}")]
    InvalidTag {
        /// Byte offset of the offending tag.
        offset: usize,
    },
}

//! FIX fields and their typed value converters.

use rust_decimal::Decimal;
use time::OffsetDateTime;

use crate::error::FieldError;

/// A single FIX field: a tag number and its raw (wire) value bytes.
///
/// Raw bytes are preserved verbatim so re-encoding reproduces the original representation
/// (round-trip fidelity, FR-B9). Typed accessors convert on demand and never panic.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Field {
    tag: u32,
    value: Vec<u8>,
}

impl Field {
    /// Create a field from a tag and raw value bytes.
    pub fn new(tag: u32, value: impl Into<Vec<u8>>) -> Self {
        Self {
            tag,
            value: value.into(),
        }
    }

    /// Create a field from a tag and a string value.
    pub fn string(tag: u32, value: &str) -> Self {
        Self::new(tag, value.as_bytes().to_vec())
    }

    /// Create an integer-valued field.
    pub fn int(tag: u32, value: i64) -> Self {
        Self::new(tag, value.to_string().into_bytes())
    }

    /// The field's tag number.
    pub fn tag(&self) -> u32 {
        self.tag
    }

    /// The raw value bytes.
    pub fn value_bytes(&self) -> &[u8] {
        &self.value
    }

    /// The value as a UTF-8 string slice.
    pub fn as_str(&self) -> Result<&str, FieldError> {
        core::str::from_utf8(&self.value).map_err(|_| FieldError::NotUtf8 { tag: self.tag })
    }

    /// The value as an integer.
    pub fn as_int(&self) -> Result<i64, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotInt {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a fixed-precision decimal (FIX Price/Qty/Amt).
    pub fn as_decimal(&self) -> Result<Decimal, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotDecimal {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a single character (FIX char).
    pub fn as_char(&self) -> Result<char, FieldError> {
        let s = self.as_str()?;
        let mut chars = s.chars();
        match (chars.next(), chars.next()) {
            (Some(c), None) => Ok(c),
            _ => Err(FieldError::NotChar {
                tag: self.tag,
                value: s.to_owned(),
            }),
        }
    }

    /// The value as a boolean (`Y`/`N`).
    pub fn as_bool(&self) -> Result<bool, FieldError> {
        match self.value.as_slice() {
            b"Y" => Ok(true),
            b"N" => Ok(false),
            _ => Err(FieldError::NotBool {
                tag: self.tag,
                value: String::from_utf8_lossy(&self.value).into_owned(),
            }),
        }
    }

    /// The value as a UTC timestamp. Accepts up to picosecond fractional digits and
    /// truncates to nanosecond resolution (FR-B7).
    pub fn as_utc_timestamp(&self) -> Result<OffsetDateTime, FieldError> {
        let s = self.as_str()?;
        parse_utc_timestamp(s).ok_or_else(|| FieldError::NotTimestamp {
            tag: self.tag,
            value: s.to_owned(),
        })
    }
}

/// Parse `YYYYMMDD-HH:MM:SS[.fraction]` as UTC. Returns `None` on any malformation.
fn parse_utc_timestamp(s: &str) -> Option<OffsetDateTime> {
    let (date, time_part) = s.split_once('-')?;
    if date.len() != 8 {
        return None;
    }
    let year: i32 = date.get(0..4)?.parse().ok()?;
    let month: u8 = date.get(4..6)?.parse().ok()?;
    let day: u8 = date.get(6..8)?.parse().ok()?;

    let (hms, frac) = match time_part.split_once('.') {
        Some((h, f)) => (h, Some(f)),
        None => (time_part, None),
    };
    let mut parts = hms.split(':');
    let hour: u8 = parts.next()?.parse().ok()?;
    let min: u8 = parts.next()?.parse().ok()?;
    let sec: u8 = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }

    // Accept >= 1 fractional digits up to picosecond; truncate to nanosecond (first 9 digits).
    let nanos: u32 = match frac {
        None => 0,
        Some(f) => {
            if f.is_empty() || !f.bytes().all(|b| b.is_ascii_digit()) {
                return None;
            }
            let mut buf = [b'0'; 9];
            for (slot, digit) in buf.iter_mut().zip(f.bytes()) {
                *slot = digit;
            }
            core::str::from_utf8(&buf).ok()?.parse().ok()?
        }
    };

    let month = time::Month::try_from(month).ok()?;
    let date = time::Date::from_calendar_date(year, month, day).ok()?;
    let time = time::Time::from_hms_nano(hour, min, sec, nanos).ok()?;
    Some(time::PrimitiveDateTime::new(date, time).assume_utc())
}

//! Standard FIX tag numbers and header/trailer classification (version-agnostic core set).
//!
//! This is the minimal session-level set used to route fields into header/body/trailer when
//! decoding without a dictionary. The full per-version classification lives in `truefix-dict`.

/// SOH (Start Of Header) field separator byte.
pub const SOH: u8 = 0x01;

/// BeginString (always first).
pub const BEGIN_STRING: u32 = 8;
/// BodyLength (always second).
pub const BODY_LENGTH: u32 = 9;
/// MsgType (always third).
pub const MSG_TYPE: u32 = 35;
/// CheckSum (always last).
pub const CHECK_SUM: u32 = 10;
/// MsgSeqNum.
pub const MSG_SEQ_NUM: u32 = 34;
/// SenderCompID.
pub const SENDER_COMP_ID: u32 = 49;
/// TargetCompID.
pub const TARGET_COMP_ID: u32 = 56;
/// SendingTime.
pub const SENDING_TIME: u32 = 52;

/// Returns `true` if `tag` is a standard session-level header field.
pub fn is_header(tag: u32) -> bool {
    matches!(
        tag,
        8 | 9
            | 35
            | 49
            | 56
            | 115
            | 128
            | 90
            | 91
            | 34
            | 50
            | 142
            | 57
            | 143
            | 116
            | 144
            | 129
            | 145
            | 43
            | 97
            | 52
            | 122
            | 212
            | 213
            | 347
            | 369
            | 370
    )
}

/// Returns `true` if `tag` is a standard trailer field.
pub fn is_trailer(tag: u32) -> bool {
    matches!(tag, 93 | 89 | 10)
}

/// If `tag` is a length field, returns the tag of the binary data field that immediately
/// follows it (whose value is exactly that many bytes and may contain SOH).
pub fn data_field_for_length(tag: u32) -> Option<u32> {
    Some(match tag {
        90 => 91,   // SecureDataLen -> SecureData
        95 => 96,   // RawDataLength -> RawData
        212 => 213, // XmlDataLen -> XmlData
        348 => 349, // EncodedIssuerLen -> EncodedIssuer
        350 => 351, // EncodedSecurityDescLen -> EncodedSecurityDesc
        352 => 353, // EncodedListExecInstLen -> EncodedListExecInst
        354 => 355, // EncodedTextLen -> EncodedText
        356 => 357, // EncodedSubjectLen -> EncodedSubject
        358 => 359, // EncodedHeadlineLen -> EncodedHeadline
        360 => 361, // EncodedAllocTextLen -> EncodedAllocText
        362 => 363, // EncodedUnderlyingIssuerLen -> EncodedUnderlyingIssuer
        364 => 365, // EncodedUnderlyingSecurityDescLen -> EncodedUnderlyingSecurityDesc
        _ => return None,
    })
}

//! Repeating-group builder.
//!
//! A group is a count tag (NoXxx) plus ordered entries; each entry is a [`FieldMap`] whose
//! first field is the group delimiter. Dictionary-driven *parsing* of groups from a flat
//! wire message is added in `truefix-dict` (Stage S4); this type lets callers *build* and
//! *encode* groups (including nested ones) today.

use crate::field_map::FieldMap;

/// A repeating group: a count tag plus its ordered entries.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Group {
    count_tag: u32,
    entries: Vec<FieldMap>,
}

impl Group {
    /// Create an empty group for the given NoXxx count tag.
    pub fn new(count_tag: u32) -> Self {
        Self {
            count_tag,
            entries: Vec::new(),
        }
    }

    /// Append an entry; returns `&mut self` for chaining.
    pub fn add_entry(&mut self, entry: FieldMap) -> &mut Self {
        self.entries.push(entry);
        self
    }

    /// The NoXxx count tag.
    pub fn count_tag(&self) -> u32 {
        self.count_tag
    }

    /// Number of entries.
    pub fn len(&self) -> usize {
        self.entries.len()
    }

    /// Whether the group has no entries.
    pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

    /// Consume the group into `(count_tag, entries)`.
    pub(crate) fn into_parts(self) -> (u32, Vec<FieldMap>) {
        (self.count_tag, self.entries)
    }
}

//! A FIX message: header, body, and trailer field maps.

use crate::error::DecodeError;
use crate::field_map::FieldMap;
use crate::tags::{BEGIN_STRING, MSG_TYPE};

/// A FIX message split into header, body, and trailer regions.
///
/// Decoding routes session-level header tags and trailer tags to their regions; everything
/// else lands in the body. Encoding always emits the canonical order
/// `8, 9, 35, <rest of header>, <body>, <trailer except 10>, 10`.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Message {
    /// Header fields (BeginString, BodyLength, MsgType, session fields, ...).
    pub header: FieldMap,
    /// Application/body fields.
    pub body: FieldMap,
    /// Trailer fields (SignatureLength, Signature, CheckSum).
    pub trailer: FieldMap,
}

impl Message {
    /// Create an empty message.
    pub fn new() -> Self {
        Self::default()
    }

    /// The BeginString (tag 8) as a string, if present and valid UTF-8.
    pub fn begin_string(&self) -> Option<&str> {
        self.header.get(BEGIN_STRING).and_then(|f| f.as_str().ok())
    }

    /// The MsgType (tag 35) as a string, if present and valid UTF-8.
    pub fn msg_type(&self) -> Option<&str> {
        self.header.get(MSG_TYPE).and_then(|f| f.as_str().ok())
    }

    /// Encode to wire bytes (computes BodyLength and CheckSum).
    pub fn encode(&self) -> Vec<u8> {
        crate::codec::encode(self)
    }

    /// Decode from wire bytes (verifies BodyLength and CheckSum).
    pub fn decode(bytes: &[u8]) -> Result<Self, DecodeError> {
        crate::codec::decode(bytes)
    }
}

//! An ordered collection of fields and nested repeating groups.

use crate::field::Field;
use crate::group::Group;

/// One member of a [`FieldMap`]: either a plain field or a repeating group.
#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) enum Member {
    /// A plain field.
    Field(Field),
    /// A repeating group: its count tag and ordered entries.
    Group {
        /// The NoXxx count tag.
        count_tag: u32,
        /// The group entries (each a `FieldMap`).
        entries: Vec<FieldMap>,
    },
}

/// An ordered map of FIX fields (and nested groups), preserving wire order.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct FieldMap {
    members: Vec<Member>,
}

impl FieldMap {
    /// Create an empty field map.
    pub fn new() -> Self {
        Self::default()
    }

    /// Append a field, preserving insertion order (used by the decoder).
    pub fn add_field(&mut self, field: Field) {
        self.members.push(Member::Field(field));
    }

    /// Set a top-level field, replacing an existing one with the same tag, else appending.
    pub fn set(&mut self, field: Field) {
        for m in &mut self.members {
            if let Member::Field(existing) = m {
                if existing.tag() == field.tag() {
                    *existing = field;
                    return;
                }
            }
        }
        self.members.push(Member::Field(field));
    }

    /// Get the first top-level field with `tag`.
    pub fn get(&self, tag: u32) -> Option<&Field> {
        self.members.iter().find_map(|m| match m {
            Member::Field(f) if f.tag() == tag => Some(f),
            _ => None,
        })
    }

    /// Returns `true` if a top-level field with `tag` is present.
    pub fn contains(&self, tag: u32) -> bool {
        self.get(tag).is_some()
    }

    /// Append a repeating group.
    pub fn add_group(&mut self, group: Group) {
        let (count_tag, entries) = group.into_parts();
        self.members.push(Member::Group { count_tag, entries });
    }

    /// Get the entries of the first group with `count_tag`.
    pub fn group(&self, count_tag: u32) -> Option<&[FieldMap]> {
        self.members.iter().find_map(|m| match m {
            Member::Group {
                count_tag: ct,
                entries,
            } if *ct == count_tag => Some(entries.as_slice()),
            _ => None,
        })
    }

    /// Iterate the top-level fields (skipping repeating groups), in order.
    pub fn fields(&self) -> impl Iterator<Item = &Field> {
        self.members.iter().filter_map(|m| match m {
            Member::Field(f) => Some(f),
            Member::Group { .. } => None,
        })
    }

    /// Internal: ordered members, for the encoder.
    pub(crate) fn members(&self) -> &[Member] {
        &self.members
    }
}

//! Typed message dispatch contract.

use crate::message::Message;

/// Dispatches an inbound message to a per-message-type handler.
///
/// Full typed dispatch over the generated messages arrives with the dictionary codegen
/// (Stage S4); this is the core contract skeleton.
pub trait MessageCracker {
    /// Error a handler may return (e.g. a business reject).
    type Error;

    /// Dispatch `message` to the handler for its message type.
    fn crack(&mut self, message: &Message) -> Result<(), Self::Error>;
}

//! Message construction contract.

use crate::message::Message;

/// Constructs empty messages for a given protocol version and message type.
///
/// The dictionary-backed implementation (typed messages) arrives in `truefix-dict`
/// (Stage S4); this is the core contract skeleton.
pub trait MessageFactory {
    /// Create an empty message for `begin_string` (e.g. `"FIX.4.4"`) and `msg_type`.
    fn create(&self, begin_string: &str, msg_type: &str) -> Message;
}

//! The SOH wire codec: [`encode`] and [`decode`].

mod decode;
mod encode;

pub use decode::decode;
pub use encode::encode;

//! Encode a [`Message`] to wire bytes, computing BodyLength (tag 9) and CheckSum (tag 10).

use crate::field_map::{FieldMap, Member};
use crate::message::Message;
use crate::tags::{BEGIN_STRING, BODY_LENGTH, CHECK_SUM, MSG_TYPE, SOH};

/// Encode `msg` to SOH-delimited wire bytes.
///
/// Emits the canonical order `8, 9, 35, <rest of header>, <body>, <trailer except 10>, 10`.
/// BodyLength is the byte count of everything after the `9=..<SOH>` up to and including the
/// `<SOH>` before `10=`; CheckSum is the sum of all preceding bytes modulo 256.
pub fn encode(msg: &Message) -> Vec<u8> {
    let begin = msg
        .header
        .get(BEGIN_STRING)
        .map(|f| f.value_bytes().to_vec())
        .unwrap_or_default();
    let msg_type = msg
        .header
        .get(MSG_TYPE)
        .map(|f| f.value_bytes().to_vec())
        .unwrap_or_default();

    // Everything counted by BodyLength: MsgType, the rest of the header, the body, and the
    // trailer (excluding CheckSum).
    let mut middle = Vec::new();
    render_raw(MSG_TYPE, &msg_type, &mut middle);
    render_members(
        &msg.header,
        &[BEGIN_STRING, BODY_LENGTH, MSG_TYPE],
        &mut middle,
    );
    render_members(&msg.body, &[], &mut middle);
    render_members(&msg.trailer, &[CHECK_SUM], &mut middle);

    let mut out = Vec::new();
    render_raw(BEGIN_STRING, &begin, &mut out);
    render_raw(BODY_LENGTH, middle.len().to_string().as_bytes(), &mut out);
    out.extend_from_slice(&middle);

    let checksum: u32 = out.iter().map(|&b| u32::from(b)).sum::<u32>() & 0xFF;
    render_raw(CHECK_SUM, format!("{checksum:03}").as_bytes(), &mut out);
    out
}

fn render_members(map: &FieldMap, skip: &[u32], out: &mut Vec<u8>) {
    for member in map.members() {
        match member {
            Member::Field(f) => {
                if !skip.contains(&f.tag()) {
                    render_raw(f.tag(), f.value_bytes(), out);
                }
            }
            Member::Group { count_tag, entries } => {
                render_raw(*count_tag, entries.len().to_string().as_bytes(), out);
                for entry in entries {
                    render_members(entry, &[], out);
                }
            }
        }
    }
}

fn render_raw(tag: u32, value: &[u8], out: &mut Vec<u8>) {
    out.extend_from_slice(tag.to_string().as_bytes());
    out.push(b'=');
    out.extend_from_slice(value);
    out.push(SOH);
}

//! Decode wire bytes into a [`Message`], verifying BodyLength (tag 9) and CheckSum (tag 10).
//!
//! Decoding produces flat ordered fields (no dictionary-driven group parsing at this layer).
//! Binary length-prefixed data fields (e.g. RawDataLength/RawData) are handled so embedded
//! SOH bytes do not corrupt parsing. No path panics.

use crate::error::DecodeError;
use crate::field::Field;
use crate::message::Message;
use crate::tags::{
    data_field_for_length, is_header, is_trailer, BEGIN_STRING, BODY_LENGTH, CHECK_SUM, SOH,
};

/// A tokenized field: tag, raw value bytes, and the byte offset where the field began.
type Token = (u32, Vec<u8>, usize);

/// Decode `input` into a [`Message`].
pub fn decode(input: &[u8]) -> Result<Message, DecodeError> {
    if input.is_empty() {
        return Err(DecodeError::Empty);
    }

    let fields = tokenize(input)?;

    let first = fields.first().ok_or(DecodeError::Empty)?;
    if first.0 != BEGIN_STRING {
        return Err(DecodeError::MissingBeginString);
    }
    let second = fields.get(1).ok_or(DecodeError::InvalidBodyLength)?;
    if second.0 != BODY_LENGTH {
        return Err(DecodeError::InvalidBodyLength);
    }
    let declared_bl = parse_usize(&second.1).ok_or(DecodeError::InvalidBodyLength)?;

    let last = fields.last().ok_or(DecodeError::MissingChecksum)?;
    if last.0 != CHECK_SUM {
        return Err(DecodeError::MissingChecksum);
    }
    let declared_cs = parse_u32(&last.1).ok_or(DecodeError::MissingChecksum)?;

    // Body starts at the third field (just after `9=..<SOH>`) and ends just before `10=`.
    let cs_offset = last.2;
    let body_start = fields.get(2).map_or(cs_offset, |f| f.2);
    let actual_bl = cs_offset
        .checked_sub(body_start)
        .ok_or(DecodeError::InvalidBodyLength)?;
    if actual_bl != declared_bl {
        return Err(DecodeError::BodyLengthMismatch {
            declared: declared_bl,
            actual: actual_bl,
        });
    }

    let pre = input.get(..cs_offset).ok_or(DecodeError::MissingChecksum)?;
    let computed: u32 = pre.iter().map(|&b| u32::from(b)).sum::<u32>() & 0xFF;
    if computed != declared_cs {
        return Err(DecodeError::ChecksumMismatch {
            declared: declared_cs,
            computed,
        });
    }

    let mut msg = Message::new();
    for (tag, value, _) in fields {
        let field = Field::new(tag, value);
        if is_trailer(tag) {
            msg.trailer.add_field(field);
        } else if is_header(tag) {
            msg.header.add_field(field);
        } else {
            msg.body.add_field(field);
        }
    }
    Ok(msg)
}

/// Split `input` into `tag=value<SOH>` tokens, honoring length-prefixed binary data fields.
fn tokenize(input: &[u8]) -> Result<Vec<Token>, DecodeError> {
    let mut tokens = Vec::new();
    let mut pos = 0usize;
    // When the previous field was a length field, this holds the exact byte length of the
    // next (data) field's value.
    let mut pending_data_len: Option<usize> = None;

    while pos < input.len() {
        let start = pos;
        let rest = input
            .get(pos..)
            .ok_or(DecodeError::Truncated { offset: start })?;

        let eq_rel = memchr(rest, b'=').ok_or(DecodeError::GarbledField {
            offset: start,
            reason: "missing '=' in field",
        })?;
        let tag_bytes = rest.get(..eq_rel).unwrap_or(&[]);
        let tag = parse_u32(tag_bytes).ok_or(DecodeError::InvalidTag { offset: start })?;
        let val_start = pos + eq_rel + 1;

        let (value, next) = if let Some(len) = pending_data_len.take() {
            let val_end = val_start
                .checked_add(len)
                .ok_or(DecodeError::GarbledField {
                    offset: start,
                    reason: "data length overflow",
                })?;
            let v = input
                .get(val_start..val_end)
                .ok_or(DecodeError::Truncated { offset: val_start })?;
            match input.get(val_end) {
                Some(&b) if b == SOH => (v.to_vec(), val_end + 1),
                _ => {
                    return Err(DecodeError::GarbledField {
                        offset: val_end,
                        reason: "data field not terminated by SOH",
                    })
                }
            }
        } else {
            let after = input
                .get(val_start..)
                .ok_or(DecodeError::Truncated { offset: val_start })?;
            let soh_rel = memchr(after, SOH).ok_or(DecodeError::GarbledField {
                offset: val_start,
                reason: "field not terminated by SOH",
            })?;
            let v = after.get(..soh_rel).unwrap_or(&[]);
            (v.to_vec(), val_start + soh_rel + 1)
        };

        if pending_data_len.is_none() && data_field_for_length(tag).is_some() {
            if let Some(len) = parse_usize(&value) {
                pending_data_len = Some(len);
            }
        }

        tokens.push((tag, value, start));
        pos = next;
    }

    Ok(tokens)
}

fn memchr(haystack: &[u8], needle: u8) -> Option<usize> {
    haystack.iter().position(|&b| b == needle)
}

fn parse_u32(bytes: &[u8]) -> Option<u32> {
    core::str::from_utf8(bytes).ok()?.parse().ok()
}

fn parse_usize(bytes: &[u8]) -> Option<usize> {
    core::str::from_utf8(bytes).ok()?.parse().ok()
}

//! T099 — reference wire vectors captured from QuickFIX/J test resources (data).
//!
//! These are reference *messages* (wire bytes) used to cross-validate that TrueFix's framing,
//! BodyLength, and CheckSum agree with QuickFIX/J on real data. `decode` verifies BodyLength and
//! CheckSum, so a successful decode of each vector is the cross-check, and re-encoding proves
//! byte-exact fidelity (FR-B9, SC-002).
//!
//! Coverage note: this captures the cleanly-verifiable vectors available in the QuickFIX/J test
//! resources. Expanding to the full canonical set across every FIX version is a follow-up that
//! builds QuickFIX/J to emit additional output vectors.

use truefix_core::{decode, encode};

const FIX44_LOGON_RAWDATA: &[u8] = include_bytes!("fixtures/reference/fix44_logon_rawdata.fix");
const FIX44_NOS_GROUP: &[u8] = include_bytes!("fixtures/reference/fix44_newordersingle_group.fix");

const ALL: &[&[u8]] = &[FIX44_LOGON_RAWDATA, FIX44_NOS_GROUP];

#[test]
fn reference_vectors_decode_and_validate() {
    // decode() validates BodyLength + CheckSum against the reference bytes.
    for v in ALL {
        assert!(
            decode(v).is_ok(),
            "reference vector failed to validate: {:?}",
            String::from_utf8_lossy(v)
        );
    }
}

#[test]
fn reference_vectors_roundtrip_byte_identical() {
    for v in ALL {
        let m = decode(v).unwrap();
        assert_eq!(encode(&m), *v, "{:?}", String::from_utf8_lossy(v));
    }
}

#[test]
fn rawdata_field_preserved_exactly() {
    let m = decode(FIX44_LOGON_RAWDATA).unwrap();
    assert_eq!(m.body.get(96).unwrap().value_bytes(), b"rawdata");
}

//! T010 — round-trip + byte-exact BodyLength/CheckSum.
//!
//! `V_RAW` is a known-good wire vector (FIX-spec-determined data, BodyLength 21, CheckSum 086)
//! used as an external anchor. The QuickFIX/J cross-vectors (T099) are a later supplement.

use truefix_core::{decode, encode, Field, Message};

const V_RAW: &[u8] = b"8=FIX.4.4\x019=21\x0135=A\x0195=7\x0196=rawdata\x0110=086\x01";

#[test]
fn decodes_known_rawdata_vector() {
    let m = decode(V_RAW).unwrap();
    assert_eq!(m.begin_string(), Some("FIX.4.4"));
    assert_eq!(m.msg_type(), Some("A"));
    // length-prefixed binary data field preserved exactly
    assert_eq!(m.body.get(96).unwrap().value_bytes(), b"rawdata");
}

#[test]
fn rawdata_vector_roundtrips_byte_identical() {
    let m = decode(V_RAW).unwrap();
    assert_eq!(encode(&m), V_RAW);
}

#[test]
fn bodylength_and_checksum_recomputed_correctly() {
    let m = decode(V_RAW).unwrap();
    let s = String::from_utf8(encode(&m)).unwrap();
    assert!(s.contains("9=21\u{1}"), "{s:?}");
    assert!(s.ends_with("10=086\u{1}"), "{s:?}");
}

#[test]
fn programmatic_newordersingle_roundtrips() {
    let mut m = Message::new();
    m.header.set(Field::string(8, "FIX.4.2"));
    m.header.set(Field::string(35, "D"));
    m.header.set(Field::int(34, 1));
    m.header.set(Field::string(49, "SENDER"));
    m.header.set(Field::string(56, "TARGET"));
    m.header.set(Field::string(52, "20240101-12:00:00"));
    m.body.set(Field::string(11, "ORDER1"));
    m.body.set(Field::string(55, "AAPL"));
    m.body.set(Field::int(54, 1));
    m.body.set(Field::int(38, 100));
    m.body.set(Field::string(40, "2"));
    m.body.set(Field::string(44, "150.25"));

    let bytes = encode(&m);
    let decoded = decode(&bytes).unwrap();

    // encode->decode->encode is byte-stable
    assert_eq!(encode(&decoded), bytes);
    // typed access survives the round-trip
    assert_eq!(decoded.body.get(55).unwrap().as_str().unwrap(), "AAPL");
    assert_eq!(
        decoded
            .body
            .get(44)
            .unwrap()
            .as_decimal()
            .unwrap()
            .to_string(),
        "150.25"
    );
    // header was classified correctly
    assert_eq!(decoded.header.get(49).unwrap().as_str().unwrap(), "SENDER");
}

//! T009 — table-driven field type / converter tests.

use truefix_core::Field;

#[test]
fn typed_conversions_succeed() {
    let cases_int = [(38u32, "100", 100i64), (34, "1", 1), (34, "-5", -5)];
    for (tag, raw, want) in cases_int {
        assert_eq!(Field::string(tag, raw).as_int().unwrap(), want, "tag {tag}");
    }

    assert_eq!(
        Field::string(44, "150.25")
            .as_decimal()
            .unwrap()
            .to_string(),
        "150.25"
    );
    assert_eq!(Field::string(35, "D").as_char().unwrap(), 'D');
    assert!(Field::string(43, "Y").as_bool().unwrap());
    assert!(!Field::string(43, "N").as_bool().unwrap());
    assert_eq!(Field::string(55, "AAPL").as_str().unwrap(), "AAPL");
    assert_eq!(Field::int(38, 100).value_bytes(), b"100");
}

#[test]
fn bad_conversions_error_never_panic() {
    assert!(Field::string(38, "x").as_int().is_err());
    assert!(Field::string(44, "x").as_decimal().is_err());
    assert!(Field::string(35, "AB").as_char().is_err());
    assert!(Field::string(35, "").as_char().is_err());
    assert!(Field::string(43, "Maybe").as_bool().is_err());
}

#[test]
fn utc_timestamp_nanosecond_and_picosecond_truncation() {
    let with_ms = Field::string(52, "20120331-10:15:30.444")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(with_ms.year(), 2012);
    assert_eq!(with_ms.nanosecond(), 444_000_000);

    // Picosecond input accepted, stored truncated to nanosecond (FR-B7).
    let with_ps = Field::string(52, "20120331-10:15:30.123456789012")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(with_ps.nanosecond(), 123_456_789);

    let no_frac = Field::string(52, "20120331-10:15:30")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(no_frac.nanosecond(), 0);
}

#[test]
fn invalid_timestamp_errors() {
    assert!(Field::string(52, "not-a-time").as_utc_timestamp().is_err());
    assert!(Field::string(52, "20121331-10:15:30") // month 13
        .as_utc_timestamp()
        .is_err());
    assert!(Field::string(52, "20120331-25:00:00") // hour 25
        .as_utc_timestamp()
        .is_err());
}

//! T012 — repeating-group model + encode (dictionary-driven group *parsing* is Stage S4).

use truefix_core::{decode, encode, Field, FieldMap, Group, Message};

#[test]
fn build_group_encodes_to_known_vector() {
    // Known-good wire vector (FIX-spec data): NoPartyIDs=1, BodyLength 35, CheckSum 040.
    let expected: &[u8] =
        b"8=FIX.4.4\x019=35\x0135=D\x01453=1\x01448=PARTY_1\x01447=I\x01452=6\x0110=040\x01";

    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.4"));
    msg.header.set(Field::string(35, "D"));

    let mut entry = FieldMap::new();
    entry.add_field(Field::string(448, "PARTY_1"));
    entry.add_field(Field::string(447, "I"));
    entry.add_field(Field::int(452, 6));
    let mut group = Group::new(453);
    group.add_entry(entry);
    msg.body.add_group(group);

    assert_eq!(encode(&msg), expected);
}

#[test]
fn empty_group_renders_zero_count() {
    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.2"));
    msg.header.set(Field::string(35, "D"));
    msg.body.add_group(Group::new(453));

    let s = String::from_utf8(encode(&msg)).unwrap();
    assert!(s.contains("453=0\u{1}"), "{s:?}");
}

#[test]
fn nested_group_roundtrips_at_byte_level() {
    // Build a group whose entry contains a nested group, encode it, then confirm a flat
    // decode re-encodes to identical bytes (group-aware decode arrives in S4).
    let mut nested_entry = FieldMap::new();
    nested_entry.add_field(Field::string(524, "SUBPARTY"));
    let mut nested = Group::new(523);
    nested.add_entry(nested_entry);

    let mut outer_entry = FieldMap::new();
    outer_entry.add_field(Field::string(448, "P1"));
    outer_entry.add_field(Field::string(447, "I"));
    outer_entry.add_group(nested);
    let mut outer = Group::new(453);
    outer.add_entry(outer_entry);

    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.4"));
    msg.header.set(Field::string(35, "D"));
    msg.body.add_group(outer);

    let bytes = encode(&msg);
    let decoded = decode(&bytes).unwrap();
    assert_eq!(encode(&decoded), bytes);
}

//! T011 — negative codec tests: typed errors, never panic (FR-B8, SC-005).

use truefix_core::{decode, DecodeError};

#[test]
fn empty_input() {
    assert_eq!(decode(b""), Err(DecodeError::Empty));
}

#[test]
fn missing_begin_string() {
    assert_eq!(decode(b"1=2\x01"), Err(DecodeError::MissingBeginString));
}

#[test]
fn invalid_tag() {
    assert!(matches!(
        decode(b"8=FIX.4.2\x01XY=1\x01"),
        Err(DecodeError::InvalidTag { .. })
    ));
}

#[test]
fn checksum_mismatch() {
    let bad = b"8=FIX.4.4\x019=21\x0135=A\x0195=7\x0196=rawdata\x0110=000\x01";
    assert!(matches!(
        decode(bad),
        Err(DecodeError::ChecksumMismatch { .. })
    ));
}

#[test]
fn body_length_mismatch() {
    let bad = b"8=FIX.4.4\x019=20\x0135=A\x0195=7\x0196=rawdata\x0110=086\x01";
    assert!(matches!(
        decode(bad),
        Err(DecodeError::BodyLengthMismatch { .. })
    ));
}

#[test]
fn truncated_field_without_soh() {
    assert!(decode(b"8=FIX.4.2\x0135=A").is_err());
}

#[test]
fn missing_separator() {
    assert!(matches!(
        decode(b"8FIX\x01"),
        Err(DecodeError::GarbledField { .. })
    ));
}

