use framing::frame_length;

/// Optional per-session services: a persistent message store and a log.
#[derive(Clone, Default)]
pub struct Services {
    /// Persistent store for sequence-number continuity (and future cross-restart resend).
    pub store: Option<Arc<dyn MessageStore>>,
    /// Message/event log.
    pub log: Option<Arc<dyn Log>>,
}

/// Control messages to a running session task.
enum Control {
    /// Begin a graceful logout.
    Logout,
}

/// A handle to a running session task.
pub struct SessionHandle {
    control: mpsc::Sender<Control>,
    task: JoinHandle<()>,
}

impl SessionHandle {
    /// Request a graceful logout.
    pub async fn logout(&self) {
        let _ = self.control.send(Control::Logout).await;
    }

    /// Wait for the session task to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Connect out as an initiator and run the session.
pub async fn connect_initiator<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    connect_initiator_with(addr, config, app, Services::default()).await
}

/// Connect out as an initiator with persistent store/log services.
pub async fn connect_initiator_with<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    let stream = TcpStream::connect(addr).await?;
    Ok(spawn_session(stream, config, app, services))
}

/// A listening acceptor that serves one static session configuration per connection.
pub struct Acceptor<A: Application + 'static> {
    listener: TcpListener,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
}

impl<A: Application + 'static> Acceptor<A> {
    /// Bind to `addr`.
    pub async fn bind(addr: SocketAddr, config: SessionConfig, app: Arc<A>) -> io::Result<Self> {
        Self::bind_with(addr, config, app, Services::default()).await
    }

    /// Bind to `addr` with persistent store/log services.
    pub async fn bind_with(
        addr: SocketAddr,
        config: SessionConfig,
        app: Arc<A>,
        services: Services,
    ) -> io::Result<Self> {
        let listener = TcpListener::bind(addr).await?;
        Ok(Self {
            listener,
            config,
            app,
            services,
        })
    }

    /// The bound local address (useful when binding to port 0).
    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.listener.local_addr()
    }

    /// Spawn the accept loop. Each connection is served as a session.
    pub fn serve(self) -> JoinHandle<()> {
        tokio::spawn(async move {
            while let Ok((stream, _peer)) = self.listener.accept().await {
                let _ = spawn_session(
                    stream,
                    self.config.clone(),
                    self.app.clone(),
                    self.services.clone(),
                );
            }
        })
    }
}

fn spawn_session<A>(
    stream: TcpStream,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> SessionHandle
where
    A: Application + 'static,
{
    let (control_tx, control_rx) = mpsc::channel(8);
    let task = tokio::spawn(async move {
        run_connection(stream, config, app, services, control_rx).await;
    });
    SessionHandle {
        control: control_tx,
        task,
    }
}

async fn run_connection<A>(
    mut stream: TcpStream,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    mut control: mpsc::Receiver<Control>,
) where
    A: Application + 'static,
{
    let mut session = Session::new(config);
    let id = session.id().clone();
    app.on_create(&id).await;

    // Restore sequence numbers from the store (continuity across restarts).
    if let Some(store) = &services.store {
        let out = store.next_sender_seq().await.unwrap_or(1);
        let inn = store.next_target_seq().await.unwrap_or(1);
        session.seed_sequences(out, inn);
    }

    let mut buf: Vec<u8> = Vec::new();
    let mut chunk = [0u8; 4096];
    let mut ticker = interval(Duration::from_secs(1));
    ticker.set_missed_tick_behavior(MissedTickBehavior::Delay);

    let mut logged_on = false;
    let mut control_open = true;
    let mut closing = false;

    if dispatch(&mut session, Event::Connected, &mut stream, &app, &id, &services, &mut logged_on)
        .await
        .is_err()
    {
        closing = true;
    }

    while !closing {
        tokio::select! {
            read = stream.read(&mut chunk) => match read {
                Ok(0) | Err(_) => break,
                Ok(n) => {
                    if let Some(slice) = chunk.get(..n) {
                        buf.extend_from_slice(slice);
                    }
                    if drain_messages(&mut buf, &mut session, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
            },
            _ = ticker.tick() => {
                if dispatch(&mut session, Event::Tick, &mut stream, &app, &id, &services, &mut logged_on)
                    .await
                    .is_err()
                {
                    closing = true;
                }
            },
            ctrl = recv_control(&mut control, control_open) => match ctrl {
                Some(Control::Logout) => {
                    if dispatch(&mut session, Event::StartLogout, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
                None => control_open = false,
            },
        }
    }

    let _ = stream.shutdown().await;
    if logged_on {
        app.on_logout(&id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logout"));
        }
    }
}

/// Await a control message, or never resolve once the channel is closed (avoids a busy loop).
async fn recv_control(control: &mut mpsc::Receiver<Control>, open: bool) -> Option<Control> {
    if open {
        control.recv().await
    } else {
        pending::<Option<Control>>().await
    }
}

#[allow(clippy::too_many_arguments)]
async fn drain_messages<A>(
    buf: &mut Vec<u8>,
    session: &mut Session,
    stream: &mut TcpStream,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
{
    loop {
        match frame_length(buf) {
            Ok(Some(total)) => {
                let raw: Vec<u8> = buf.drain(..total).collect();
                if let Ok(msg) = decode(&raw) {
                    if let Some(log) = &services.log {
                        log.on_incoming(&String::from_utf8_lossy(&raw));
                    }
                    let inbound_ok = if is_admin(&msg) {
                        app.from_admin(&msg, id).await.is_ok()
                    } else {
                        app.from_app(&msg, id).await.is_ok()
                    };
                    dispatch(session, Event::Received(msg), stream, app, id, services, logged_on)
                        .await?;
                    if !inbound_ok {
                        return Err(());
                    }
                }
                // Garbled frames are dropped at this stage; RejectGarbledMessage arrives in S3.
            }
            Ok(None) => return Ok(()),
            Err(_) => {
                buf.clear();
                return Ok(());
            }
        }
    }
}

/// Run the engine for one event and perform the resulting actions. Returns `Err` if the
/// session should be torn down.
#[allow(clippy::too_many_arguments)]
async fn dispatch<A>(
    session: &mut Session,
    event: Event,
    stream: &mut TcpStream,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
{
    let actions = session.handle(event);

    if !*logged_on && session.is_logged_on() {
        *logged_on = true;
        app.on_logon(id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logon"));
        }
    }

    let mut disconnect = false;
    for action in actions {
        match action {
            Action::Send(mut msg) => {
                if is_admin(&msg) {
                    app.to_admin(&mut msg, id).await;
                } else {
                    app.to_app(&mut msg, id).await;
                }
                let bytes = msg.encode();
                if let Some(log) = &services.log {
                    log.on_outgoing(&String::from_utf8_lossy(&bytes));
                }
                if stream.write_all(&bytes).await.is_err() {
                    return Err(());
                }
            }
            Action::Disconnect => disconnect = true,
        }
    }
    let _ = stream.flush().await;

    // Persist sequence numbers for restart continuity (best-effort).
    if let Some(store) = &services.store {
        let _ = store.set_next_sender_seq(session.next_out_seq()).await;
        let _ = store.set_next_target_seq(session.next_in_seq()).await;
    }

    if disconnect || session.state() == SessionState::Disconnected {
        Err(())
    } else {
        Ok(())
    }
}

fn is_admin(msg: &Message) -> bool {
    matches!(msg.msg_type(), Some("0" | "1" | "2" | "3" | "4" | "5" | "A"))
}

//! Extract complete FIX messages from a byte stream.

use truefix_core::DecodeError;

const SOH: u8 = 0x01;

/// If `buf` begins with at least one complete FIX message, return `Ok(Some(total_len))` (the
/// byte length of that message). Return `Ok(None)` if more bytes are needed, or `Err` if the
/// start of the buffer cannot be framed.
///
/// Uses BodyLength (tag 9) to locate the body, then accounts for the fixed 7-byte
/// `10=XXX<SOH>` CheckSum trailer.
pub(crate) fn frame_length(buf: &[u8]) -> Result<Option<usize>, DecodeError> {
    let Some(soh1) = find(buf, SOH) else {
        return Ok(None);
    };
    if buf.get(0..2) != Some(b"8=") {
        return Err(DecodeError::MissingBeginString);
    }

    let after8 = buf.get(soh1 + 1..).unwrap_or(&[]);
    let Some(soh2_rel) = find(after8, SOH) else {
        return Ok(None);
    };
    let bl_field = after8.get(..soh2_rel).unwrap_or(&[]);
    if bl_field.get(0..2) != Some(b"9=") {
        return Err(DecodeError::InvalidBodyLength);
    }
    let bl_val = bl_field.get(2..).unwrap_or(&[]);
    let body_len: usize = core::str::from_utf8(bl_val)
        .ok()
        .and_then(|s| s.parse().ok())
        .ok_or(DecodeError::InvalidBodyLength)?;

    let body_start = soh1 + 1 + soh2_rel + 1;
    // CheckSum field "10=" + 3 digits + SOH is always 7 bytes.
    let total = body_start + body_len + 7;
    if buf.len() >= total {
        Ok(Some(total))
    } else {
        Ok(None)
    }
}

fn find(haystack: &[u8], needle: u8) -> Option<usize> {
    haystack.iter().position(|&b| b == needle)
}

#[cfg(test)]
mod tests {
    use super::*;

    const MSG: &[u8] = b"8=FIX.4.4\x019=21\x0135=A\x0195=7\x0196=rawdata\x0110=086\x01";

    #[test]
    fn frames_complete_message() {
        assert_eq!(frame_length(MSG), Ok(Some(MSG.len())));
    }

    #[test]
    fn needs_more_bytes() {
        assert_eq!(frame_length(&MSG[..10]), Ok(None));
        assert_eq!(frame_length(b"8=FIX.4.4"), Ok(None));
    }

    #[test]
    fn detects_two_messages_in_buffer() {
        let mut two = MSG.to_vec();
        two.extend_from_slice(MSG);
        assert_eq!(frame_length(&two), Ok(Some(MSG.len())));
    }
}

//! T022 — two-process (two-task) logon -> heartbeat -> logout over real TCP.
//!
//! Runs an acceptor and an initiator on loopback and drives a full session handshake, sustained
//! heartbeats, and a graceful bilateral logout. Validated on FIX 4.2 and FIX 4.4.

use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::Duration;

use truefix_core::Message;
use truefix_session::{Application, Role, SessionConfig, SessionId};
use truefix_transport::{connect_initiator, Acceptor};

#[derive(Default)]
struct Counters {
    logged_on: AtomicBool,
    logged_out: AtomicBool,
    heartbeats: AtomicUsize,
}

struct TestApp {
    c: Arc<Counters>,
}

#[async_trait::async_trait]
impl Application for TestApp {
    async fn on_logon(&self, _s: &SessionId) {
        self.c.logged_on.store(true, Ordering::SeqCst);
    }
    async fn on_logout(&self, _s: &SessionId) {
        self.c.logged_out.store(true, Ordering::SeqCst);
    }
    async fn from_admin(&self, msg: &Message, _s: &SessionId) -> Result<(), String> {
        if msg.msg_type() == Some("0") {
            self.c.heartbeats.fetch_add(1, Ordering::SeqCst);
        }
        Ok(())
    }
}

async fn wait_until<F: Fn() -> bool>(cond: F, timeout: Duration) -> bool {
    let start = std::time::Instant::now();
    while start.elapsed() < timeout {
        if cond() {
            return true;
        }
        tokio::time::sleep(Duration::from_millis(20)).await;
    }
    cond()
}

async fn run_handshake(begin_string: &str) {
    let acc_counters = Arc::new(Counters::default());
    let init_counters = Arc::new(Counters::default());

    let mut acc_cfg = SessionConfig::new(begin_string, "SERVER", "CLIENT", Role::Acceptor);
    acc_cfg.heartbeat_interval = 1;
    let mut init_cfg = SessionConfig::new(begin_string, "CLIENT", "SERVER", Role::Initiator);
    init_cfg.heartbeat_interval = 1;

    let acceptor = Acceptor::bind(
        "127.0.0.1:0".parse().unwrap(),
        acc_cfg,
        Arc::new(TestApp {
            c: acc_counters.clone(),
        }),
    )
    .await
    .unwrap();
    let addr = acceptor.local_addr().unwrap();
    acceptor.serve();

    let handle = connect_initiator(
        addr,
        init_cfg,
        Arc::new(TestApp {
            c: init_counters.clone(),
        }),
    )
    .await
    .unwrap();

    // Both sides log on.
    assert!(
        wait_until(
            || acc_counters.logged_on.load(Ordering::SeqCst)
                && init_counters.logged_on.load(Ordering::SeqCst),
            Duration::from_secs(5),
        )
        .await,
        "{begin_string}: both sides should log on"
    );

    // Heartbeats flow both ways (hb interval = 1s).
    assert!(
        wait_until(
            || acc_counters.heartbeats.load(Ordering::SeqCst) >= 1
                && init_counters.heartbeats.load(Ordering::SeqCst) >= 1,
            Duration::from_secs(5),
        )
        .await,
        "{begin_string}: both sides should exchange heartbeats"
    );

    // Initiator starts a graceful logout; both sides log out.
    handle.logout().await;
    assert!(
        wait_until(
            || acc_counters.logged_out.load(Ordering::SeqCst)
                && init_counters.logged_out.load(Ordering::SeqCst),
            Duration::from_secs(5),
        )
        .await,
        "{begin_string}: both sides should log out"
    );

    handle.join().await;
}

#[tokio::test(flavor = "multi_thread", worker_threads = 2)]
async fn logon_heartbeat_logout_fix42() {
    run_handshake("FIX.4.2").await;
}

#[tokio::test(flavor = "multi_thread", worker_threads = 2)]
async fn logon_heartbeat_logout_fix44() {
    run_handshake("FIX.4.4").await;
}

//! `truefix-store` — pluggable persistence of sequence numbers and sent messages.
//!
//! The [`MessageStore`] trait abstracts the storage needed for resend (FR-G2): the next inbound
//! and outbound sequence numbers, and the bytes of each sent message keyed by sequence number.
//! Implementations: [`MemoryStore`], [`FileStore`], [`CachedFileStore`], [`NoopStore`], and a
//! SQL-backed store behind the `sql` feature.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod file;
mod memory;
mod noop;
#[cfg(feature = "sql")]
mod sql;

use std::path::PathBuf;

use async_trait::async_trait;
use thiserror::Error;

pub use file::{CachedFileStore, FileStore};
pub use memory::MemoryStore;
pub use noop::NoopStore;
#[cfg(feature = "sql")]
pub use sql::SqlStore;

/// An error from a message store.
#[derive(Debug, Error)]
pub enum StoreError {
    /// An underlying I/O error.
    #[error("store I/O error: {0}")]
    Io(String),
    /// A backend (e.g. SQL) error.
    #[error("store backend error: {0}")]
    Backend(String),
}

/// Persistence for sequence numbers and outbound messages, sufficient to satisfy resend
/// across restarts (FR-G2, SC-006).
#[async_trait]
pub trait MessageStore: Send + Sync {
    /// The next outbound (sender) sequence number.
    async fn next_sender_seq(&self) -> Result<u64, StoreError>;
    /// The next inbound (target) sequence number expected.
    async fn next_target_seq(&self) -> Result<u64, StoreError>;
    /// Set the next outbound sequence number.
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError>;
    /// Set the next inbound sequence number.
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError>;
    /// Persist an outbound message's bytes under its sequence number.
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError>;
    /// Retrieve stored messages whose sequence numbers fall in `[begin, end]`, in order.
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError>;
    /// Reset: clear stored messages and set both sequence numbers back to 1.
    async fn reset(&self) -> Result<(), StoreError>;
}

/// Which store backend to construct.
#[derive(Debug, Clone)]
pub enum StoreConfig {
    /// Volatile in-memory store.
    Memory,
    /// File-backed store in a directory.
    File {
        /// Directory holding the store files.
        dir: PathBuf,
    },
    /// File-backed store that also caches messages in memory.
    CachedFile {
        /// Directory holding the store files.
        dir: PathBuf,
    },
    /// No-op store (never persists; sequence numbers stay at 1).
    Noop,
    /// SQL-backed store (requires the `sql` feature).
    #[cfg(feature = "sql")]
    Sql {
        /// Database URL.
        url: String,
    },
}

/// Build a boxed [`MessageStore`] from a [`StoreConfig`].
pub async fn build_store(config: &StoreConfig) -> Result<Box<dyn MessageStore>, StoreError> {
    Ok(match config {
        StoreConfig::Memory => Box::new(MemoryStore::new()),
        StoreConfig::File { dir } => Box::new(FileStore::open(dir)?),
        StoreConfig::CachedFile { dir } => Box::new(CachedFileStore::open(dir)?),
        StoreConfig::Noop => Box::new(NoopStore),
        #[cfg(feature = "sql")]
        StoreConfig::Sql { url } => Box::new(SqlStore::connect(url).await?),
    })
}

//! Volatile in-memory message store.

use std::collections::BTreeMap;
use std::sync::Mutex;

use async_trait::async_trait;

use crate::{MessageStore, StoreError};

pub(crate) struct State {
    pub(crate) sender: u64,
    pub(crate) target: u64,
    pub(crate) messages: BTreeMap<u64, Vec<u8>>,
}

impl Default for State {
    fn default() -> Self {
        Self {
            sender: 1,
            target: 1,
            messages: BTreeMap::new(),
        }
    }
}

impl State {
    pub(crate) fn range(&self, begin: u64, end: u64) -> Vec<(u64, Vec<u8>)> {
        self.messages
            .range(begin..=end)
            .map(|(seq, bytes)| (*seq, bytes.clone()))
            .collect()
    }
}

/// An in-memory store (does not survive process restart).
#[derive(Default)]
pub struct MemoryStore {
    state: Mutex<State>,
}

impl MemoryStore {
    /// Create an empty in-memory store.
    pub fn new() -> Self {
        Self::default()
    }
}

fn lock<T>(m: &Mutex<T>) -> Result<std::sync::MutexGuard<'_, T>, StoreError> {
    m.lock()
        .map_err(|_| StoreError::Backend("poisoned lock".into()))
}

#[async_trait]
impl MessageStore for MemoryStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        Ok(lock(&self.state)?.sender)
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        Ok(lock(&self.state)?.target)
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        lock(&self.state)?.sender = seq;
        Ok(())
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        lock(&self.state)?.target = seq;
        Ok(())
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        lock(&self.state)?.messages.insert(seq, message.to_vec());
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        Ok(lock(&self.state)?.range(begin, end))
    }
    async fn reset(&self) -> Result<(), StoreError> {
        let mut s = lock(&self.state)?;
        *s = State::default();
        Ok(())
    }
}

//! File-backed message stores.
//!
//! Layout in the store directory:
//! - `seqnums` — text: sender sequence on line 1, target sequence on line 2.
//! - `body` — append log of records: `seq(8 LE) | len(4 LE) | bytes`.
//!
//! On open, the body log is replayed into memory; a truncated/corrupt trailing record is
//! tolerated (recovered up to the last complete record) and flagged, supporting
//! ForceResendWhenCorruptedStore (T060).

use std::collections::BTreeMap;
use std::fs;
use std::io::{ErrorKind, Write};
use std::path::{Path, PathBuf};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Mutex;

use async_trait::async_trait;

use crate::memory::State;
use crate::{MessageStore, StoreError};

fn io_err(e: std::io::Error) -> StoreError {
    StoreError::Io(e.to_string())
}

/// A durable, file-backed message store.
pub struct FileStore {
    seq_path: PathBuf,
    body_path: PathBuf,
    state: Mutex<State>,
    corrupted: AtomicBool,
}

impl FileStore {
    /// Open (creating if needed) a file store in `dir`.
    pub fn open(dir: &Path) -> Result<Self, StoreError> {
        fs::create_dir_all(dir).map_err(io_err)?;
        let seq_path = dir.join("seqnums");
        let body_path = dir.join("body");
        let (sender, target) = load_seqnums(&seq_path)?;
        let (messages, corrupted) = load_body(&body_path)?;
        Ok(Self {
            seq_path,
            body_path,
            state: Mutex::new(State {
                sender,
                target,
                messages,
            }),
            corrupted: AtomicBool::new(corrupted),
        })
    }

    /// Whether a corrupt trailing record was detected and recovered on open.
    pub fn was_corrupted(&self) -> bool {
        self.corrupted.load(Ordering::SeqCst)
    }

    fn lock(&self) -> Result<std::sync::MutexGuard<'_, State>, StoreError> {
        self.state
            .lock()
            .map_err(|_| StoreError::Backend("poisoned lock".into()))
    }

    fn write_seqnums(&self, sender: u64, target: u64) -> Result<(), StoreError> {
        fs::write(&self.seq_path, format!("{sender}\n{target}\n")).map_err(io_err)
    }
}

#[async_trait]
impl MessageStore for FileStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        Ok(self.lock()?.sender)
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        Ok(self.lock()?.target)
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        let target = {
            let mut s = self.lock()?;
            s.sender = seq;
            s.target
        };
        self.write_seqnums(seq, target)
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        let sender = {
            let mut s = self.lock()?;
            s.target = seq;
            s.sender
        };
        self.write_seqnums(sender, seq)
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        append_record(&self.body_path, seq, message)?;
        self.lock()?.messages.insert(seq, message.to_vec());
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        Ok(self.lock()?.range(begin, end))
    }
    async fn reset(&self) -> Result<(), StoreError> {
        {
            let mut s = self.lock()?;
            *s = State::default();
        }
        fs::write(&self.body_path, []).map_err(io_err)?;
        self.corrupted.store(false, Ordering::SeqCst);
        self.write_seqnums(1, 1)
    }
}

/// A file-backed store that also caches messages in memory for fast resend.
///
/// In Stage S5 it shares [`FileStore`]'s durable implementation; the cached variant is where
/// write-batching optimizations will live.
pub struct CachedFileStore(FileStore);

impl CachedFileStore {
    /// Open (creating if needed) a cached file store in `dir`.
    pub fn open(dir: &Path) -> Result<Self, StoreError> {
        Ok(Self(FileStore::open(dir)?))
    }

    /// Whether a corrupt trailing record was detected and recovered on open.
    pub fn was_corrupted(&self) -> bool {
        self.0.was_corrupted()
    }
}

#[async_trait]
impl MessageStore for CachedFileStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.0.next_sender_seq().await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.0.next_target_seq().await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.0.set_next_sender_seq(seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.0.set_next_target_seq(seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        self.0.save(seq, message).await
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        self.0.get(begin, end).await
    }
    async fn reset(&self) -> Result<(), StoreError> {
        self.0.reset().await
    }
}

fn load_seqnums(path: &Path) -> Result<(u64, u64), StoreError> {
    match fs::read_to_string(path) {
        Ok(s) => {
            let mut lines = s.lines();
            let sender = lines
                .next()
                .and_then(|l| l.trim().parse().ok())
                .unwrap_or(1);
            let target = lines
                .next()
                .and_then(|l| l.trim().parse().ok())
                .unwrap_or(1);
            Ok((sender, target))
        }
        Err(e) if e.kind() == ErrorKind::NotFound => Ok((1, 1)),
        Err(e) => Err(io_err(e)),
    }
}

fn load_body(path: &Path) -> Result<(BTreeMap<u64, Vec<u8>>, bool), StoreError> {
    match fs::read(path) {
        Ok(data) => Ok(parse_records(&data)),
        Err(e) if e.kind() == ErrorKind::NotFound => Ok((BTreeMap::new(), false)),
        Err(e) => Err(io_err(e)),
    }
}

/// Replay records; returns the message map and whether a corrupt trailing record was found.
fn parse_records(data: &[u8]) -> (BTreeMap<u64, Vec<u8>>, bool) {
    let mut map = BTreeMap::new();
    let mut pos = 0usize;
    loop {
        let Some(seq) = read_u64(data, pos) else {
            return (map, pos != data.len());
        };
        let Some(len) = read_u32(data, pos + 8) else {
            return (map, true);
        };
        let start = pos + 12;
        let Some(end) = start.checked_add(len as usize) else {
            return (map, true);
        };
        let Some(bytes) = data.get(start..end) else {
            return (map, true);
        };
        map.insert(seq, bytes.to_vec());
        pos = end;
    }
}

fn append_record(path: &Path, seq: u64, message: &[u8]) -> Result<(), StoreError> {
    let mut f = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map_err(io_err)?;
    f.write_all(&seq.to_le_bytes()).map_err(io_err)?;
    let len = u32::try_from(message.len())
        .map_err(|_| StoreError::Backend("message too large".into()))?;
    f.write_all(&len.to_le_bytes()).map_err(io_err)?;
    f.write_all(message).map_err(io_err)?;
    Ok(())
}

fn read_u64(data: &[u8], pos: usize) -> Option<u64> {
    let end = pos.checked_add(8)?;
    let bytes: [u8; 8] = data.get(pos..end)?.try_into().ok()?;
    Some(u64::from_le_bytes(bytes))
}

fn read_u32(data: &[u8], pos: usize) -> Option<u32> {
    let end = pos.checked_add(4)?;
    let bytes: [u8; 4] = data.get(pos..end)?.try_into().ok()?;
    Some(u32::from_le_bytes(bytes))
}

//! SQL-backed message store (JDBC-equivalent), behind the `sql` feature.

use std::str::FromStr;

use async_trait::async_trait;
use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use sqlx::Row;

use crate::{MessageStore, StoreError};

fn backend<E: std::fmt::Display>(e: E) -> StoreError {
    StoreError::Backend(e.to_string())
}

/// A SQL-backed store using `sqlx` (SQLite). Maps the QuickFIX/J JDBC store tables
/// (sequence numbers + sent messages) to a relational schema.
pub struct SqlStore {
    pool: SqlitePool,
}

impl SqlStore {
    /// Connect to `url` (e.g. `sqlite://truefix.db` or `sqlite::memory:`) and ensure the schema.
    pub async fn connect(url: &str) -> Result<Self, StoreError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(backend)?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts).await.map_err(backend)?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS seqnums (\
             id INTEGER PRIMARY KEY CHECK (id = 0), sender INTEGER NOT NULL, target INTEGER NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;
        sqlx::query("INSERT OR IGNORE INTO seqnums (id, sender, target) VALUES (0, 1, 1)")
            .execute(&pool)
            .await
            .map_err(backend)?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS messages (seq INTEGER PRIMARY KEY, data BLOB NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;

        Ok(Self { pool })
    }

    async fn get_seq(&self, column: &str) -> Result<u64, StoreError> {
        let sql = format!("SELECT {column} FROM seqnums WHERE id = 0");
        let row = sqlx::query(&sql)
            .fetch_one(&self.pool)
            .await
            .map_err(backend)?;
        let value: i64 = row.try_get(column).map_err(backend)?;
        Ok(value as u64)
    }

    async fn set_seq(&self, column: &str, seq: u64) -> Result<(), StoreError> {
        let sql = format!("UPDATE seqnums SET {column} = ? WHERE id = 0");
        sqlx::query(&sql)
            .bind(seq as i64)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

#[async_trait]
impl MessageStore for SqlStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("sender").await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("target").await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("sender", seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("target", seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        sqlx::query("INSERT OR REPLACE INTO messages (seq, data) VALUES (?, ?)")
            .bind(seq as i64)
            .bind(message)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        let rows =
            sqlx::query("SELECT seq, data FROM messages WHERE seq BETWEEN ? AND ? ORDER BY seq")
                .bind(begin as i64)
                .bind(end as i64)
                .fetch_all(&self.pool)
                .await
                .map_err(backend)?;
        let mut out = Vec::with_capacity(rows.len());
        for row in rows {
            let seq: i64 = row.try_get("seq").map_err(backend)?;
            let data: Vec<u8> = row.try_get("data").map_err(backend)?;
            out.push((seq as u64, data));
        }
        Ok(out)
    }
    async fn reset(&self) -> Result<(), StoreError> {
        sqlx::query("DELETE FROM messages")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        sqlx::query("UPDATE seqnums SET sender = 1, target = 1 WHERE id = 0")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

