//! T053 / T060 — restart-survivable resend and corrupted-store recovery.

use std::path::PathBuf;
use std::sync::atomic::{AtomicU64, Ordering};
use std::time::{SystemTime, UNIX_EPOCH};

use truefix_store::{
    build_store, CachedFileStore, FileStore, MemoryStore, MessageStore, NoopStore, StoreConfig,
};

static COUNTER: AtomicU64 = AtomicU64::new(0);

fn unique_dir() -> PathBuf {
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0);
    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
    let dir =
        std::env::temp_dir().join(format!("truefix-store-{}-{nanos}-{n}", std::process::id()));
    std::fs::create_dir_all(&dir).unwrap();
    dir
}

fn cleanup(dir: &PathBuf) {
    let _ = std::fs::remove_dir_all(dir);
}

#[tokio::test]
async fn memory_store_round_trips_within_session() {
    let s = MemoryStore::new();
    s.set_next_sender_seq(5).await.unwrap();
    s.save(2, b"msg2").await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 5);
    assert_eq!(s.get(1, 10).await.unwrap(), vec![(2, b"msg2".to_vec())]);
}

#[tokio::test]
async fn file_store_survives_restart() {
    let dir = unique_dir();
    {
        let s = FileStore::open(&dir).unwrap();
        s.set_next_sender_seq(7).await.unwrap();
        s.set_next_target_seq(3).await.unwrap();
        s.save(5, b"hello").await.unwrap();
        s.save(6, b"world").await.unwrap();
    }
    // reopen (simulated restart)
    let s2 = FileStore::open(&dir).unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 7);
    assert_eq!(s2.next_target_seq().await.unwrap(), 3);
    assert_eq!(
        s2.get(5, 6).await.unwrap(),
        vec![(5, b"hello".to_vec()), (6, b"world".to_vec())]
    );
    cleanup(&dir);
}

#[tokio::test]
async fn cached_file_store_survives_restart() {
    let dir = unique_dir();
    {
        let s = CachedFileStore::open(&dir).unwrap();
        s.set_next_sender_seq(4).await.unwrap();
        s.save(1, b"a").await.unwrap();
        s.save(2, b"bb").await.unwrap();
    }
    let s2 = CachedFileStore::open(&dir).unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 4);
    assert_eq!(s2.get(1, 2).await.unwrap().len(), 2);
    cleanup(&dir);
}

#[tokio::test]
async fn noop_store_is_inert() {
    let s = NoopStore;
    s.save(1, b"x").await.unwrap();
    s.set_next_sender_seq(9).await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 1);
    assert!(s.get(1, 10).await.unwrap().is_empty());
}

#[tokio::test]
async fn corrupted_trailing_record_is_recovered() {
    let dir = unique_dir();
    {
        let s = FileStore::open(&dir).unwrap();
        s.save(1, b"good").await.unwrap();
    }
    // Append an incomplete record header to simulate a torn write.
    let body = dir.join("body");
    let mut bytes = std::fs::read(&body).unwrap();
    bytes.extend_from_slice(&[9, 9, 9]);
    std::fs::write(&body, bytes).unwrap();

    let s2 = FileStore::open(&dir).unwrap();
    assert!(s2.was_corrupted(), "corruption should be detected");
    // the good prefix is still recovered (supports ForceResendWhenCorruptedStore)
    assert_eq!(s2.get(1, 1).await.unwrap(), vec![(1, b"good".to_vec())]);
    cleanup(&dir);
}

#[tokio::test]
async fn reset_clears_messages_and_seqs() {
    let s = MemoryStore::new();
    s.set_next_sender_seq(10).await.unwrap();
    s.save(3, b"x").await.unwrap();
    s.reset().await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 1);
    assert!(s.get(1, 100).await.unwrap().is_empty());
}

#[tokio::test]
async fn factory_builds_each_backend() {
    let dir = unique_dir();
    let configs = [
        StoreConfig::Memory,
        StoreConfig::Noop,
        StoreConfig::File { dir: dir.clone() },
        StoreConfig::CachedFile { dir: dir.clone() },
    ];
    for cfg in configs {
        let s = build_store(&cfg).await.unwrap();
        // every backend implements the trait
        let _ = s.next_sender_seq().await.unwrap();
    }
    cleanup(&dir);
}

#[cfg(feature = "sql")]
#[tokio::test]
async fn sql_store_survives_restart() {
    let dir = unique_dir();
    let url = format!("sqlite:{}/store.db", dir.display());
    {
        let s = truefix_store::SqlStore::connect(&url).await.unwrap();
        s.set_next_sender_seq(8).await.unwrap();
        s.save(3, b"sql-msg").await.unwrap();
    }
    let s2 = truefix_store::SqlStore::connect(&url).await.unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 8);
    assert_eq!(s2.get(3, 3).await.unwrap(), vec![(3, b"sql-msg".to_vec())]);
    cleanup(&dir);
}

//! `truefix-log` — pluggable FIX logging with message/event stream separation (FR-H2).
//!
//! The [`Log`] trait separates **message** logging (inbound/outbound wire messages) from
//! **event** logging (session lifecycle, errors). Implementations: [`ScreenLog`], [`FileLog`],
//! [`TracingLog`], and [`CompositeLog`] (fan-out).
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod composite;
mod file;
mod screen;
mod tracing_log;

use std::path::PathBuf;

use thiserror::Error;

pub use composite::CompositeLog;
pub use file::FileLog;
pub use screen::ScreenLog;
pub use tracing_log::TracingLog;

/// An error constructing a log.
#[derive(Debug, Error)]
pub enum LogError {
    /// An I/O error (e.g. opening a log file).
    #[error("log I/O error: {0}")]
    Io(String),
}

/// A FIX log sink. Message logging (incoming/outgoing) is kept separate from event logging.
///
/// Methods are best-effort and infallible from the caller's perspective; a sink that cannot
/// write drops the entry rather than failing the session.
pub trait Log: Send + Sync {
    /// Log an inbound wire message.
    fn on_incoming(&self, message: &str);
    /// Log an outbound wire message.
    fn on_outgoing(&self, message: &str);
    /// Log a session event.
    fn on_event(&self, text: &str);
}

/// Which log backend to construct.
#[derive(Debug, Clone)]
pub enum LogConfig {
    /// Log to stdout/stderr.
    Screen,
    /// Log to files in a directory (`messages.log` + `event.log`).
    File {
        /// Directory holding the log files.
        dir: PathBuf,
    },
    /// Log via the `tracing` facade.
    Tracing,
    /// Fan out to several logs.
    Composite(Vec<LogConfig>),
}

/// Build a boxed [`Log`] from a [`LogConfig`].
pub fn build_log(config: &LogConfig) -> Result<Box<dyn Log>, LogError> {
    Ok(match config {
        LogConfig::Screen => Box::new(ScreenLog::new()),
        LogConfig::File { dir } => Box::new(FileLog::open(dir)?),
        LogConfig::Tracing => Box::new(TracingLog::new()),
        LogConfig::Composite(parts) => {
            let mut logs: Vec<Box<dyn Log>> = Vec::with_capacity(parts.len());
            for part in parts {
                logs.push(build_log(part)?);
            }
            Box::new(CompositeLog::new(logs))
        }
    })
}

//! File log: separate `messages.log` and `event.log` streams (FR-H2).

use std::fs::{File, OpenOptions};
use std::io::Write;
use std::path::Path;
use std::sync::Mutex;

use crate::{Log, LogError};

/// Logs inbound/outbound messages to `messages.log` and events to `event.log`.
pub struct FileLog {
    messages: Mutex<File>,
    events: Mutex<File>,
}

impl FileLog {
    /// Open (creating if needed) the log files in `dir`.
    pub fn open(dir: &Path) -> Result<Self, LogError> {
        std::fs::create_dir_all(dir).map_err(|e| LogError::Io(e.to_string()))?;
        let messages = open_append(&dir.join("messages.log"))?;
        let events = open_append(&dir.join("event.log"))?;
        Ok(Self {
            messages: Mutex::new(messages),
            events: Mutex::new(events),
        })
    }
}

fn open_append(path: &Path) -> Result<File, LogError> {
    OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map_err(|e| LogError::Io(e.to_string()))
}

fn write_line(file: &Mutex<File>, line: &str) {
    if let Ok(mut f) = file.lock() {
        let _ = writeln!(f, "{line}");
    }
}

impl Log for FileLog {
    fn on_incoming(&self, message: &str) {
        write_line(&self.messages, &format!("I {message}"));
    }
    fn on_outgoing(&self, message: &str) {
        write_line(&self.messages, &format!("O {message}"));
    }
    fn on_event(&self, text: &str) {
        write_line(&self.events, text);
    }
}

//! Fan-out log.

use crate::Log;

/// Fans every entry out to each wrapped log.
pub struct CompositeLog {
    logs: Vec<Box<dyn Log>>,
}

impl CompositeLog {
    /// Create a composite over `logs`.
    pub fn new(logs: Vec<Box<dyn Log>>) -> Self {
        Self { logs }
    }
}

impl Log for CompositeLog {
    fn on_incoming(&self, message: &str) {
        for log in &self.logs {
            log.on_incoming(message);
        }
    }
    fn on_outgoing(&self, message: &str) {
        for log in &self.logs {
            log.on_outgoing(message);
        }
    }
    fn on_event(&self, text: &str) {
        for log in &self.logs {
            log.on_event(text);
        }
    }
}

