//! T053 / T060 — restart-survivable resend and corrupted-store recovery.

use std::path::PathBuf;
use std::sync::atomic::{AtomicU64, Ordering};
use std::time::{SystemTime, UNIX_EPOCH};

use truefix_store::{
    build_store, CachedFileStore, FileStore, MemoryStore, MessageStore, NoopStore, StoreConfig,
};

static COUNTER: AtomicU64 = AtomicU64::new(0);

fn unique_dir() -> PathBuf {
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0);
    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
    let dir =
        std::env::temp_dir().join(format!("truefix-store-{}-{nanos}-{n}", std::process::id()));
    std::fs::create_dir_all(&dir).unwrap();
    dir
}

fn cleanup(dir: &PathBuf) {
    let _ = std::fs::remove_dir_all(dir);
}

#[tokio::test]
async fn memory_store_round_trips_within_session() {
    let s = MemoryStore::new();
    s.set_next_sender_seq(5).await.unwrap();
    s.save(2, b"msg2").await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 5);
    assert_eq!(s.get(1, 10).await.unwrap(), vec![(2, b"msg2".to_vec())]);
}

#[tokio::test]
async fn file_store_survives_restart() {
    let dir = unique_dir();
    {
        let s = FileStore::open(&dir).unwrap();
        s.set_next_sender_seq(7).await.unwrap();
        s.set_next_target_seq(3).await.unwrap();
        s.save(5, b"hello").await.unwrap();
        s.save(6, b"world").await.unwrap();
    }
    // reopen (simulated restart)
    let s2 = FileStore::open(&dir).unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 7);
    assert_eq!(s2.next_target_seq().await.unwrap(), 3);
    assert_eq!(
        s2.get(5, 6).await.unwrap(),
        vec![(5, b"hello".to_vec()), (6, b"world".to_vec())]
    );
    cleanup(&dir);
}

#[tokio::test]
async fn cached_file_store_survives_restart() {
    let dir = unique_dir();
    {
        let s = CachedFileStore::open(&dir).unwrap();
        s.set_next_sender_seq(4).await.unwrap();
        s.save(1, b"a").await.unwrap();
        s.save(2, b"bb").await.unwrap();
    }
    let s2 = CachedFileStore::open(&dir).unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 4);
    assert_eq!(s2.get(1, 2).await.unwrap().len(), 2);
    cleanup(&dir);
}

#[tokio::test]
async fn noop_store_is_inert() {
    let s = NoopStore;
    s.save(1, b"x").await.unwrap();
    s.set_next_sender_seq(9).await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 1);
    assert!(s.get(1, 10).await.unwrap().is_empty());
}

#[tokio::test]
async fn corrupted_trailing_record_is_recovered() {
    let dir = unique_dir();
    {
        let s = FileStore::open(&dir).unwrap();
        s.save(1, b"good").await.unwrap();
    }
    // Append an incomplete record header to simulate a torn write.
    let body = dir.join("body");
    let mut bytes = std::fs::read(&body).unwrap();
    bytes.extend_from_slice(&[9, 9, 9]);
    std::fs::write(&body, bytes).unwrap();

    let s2 = FileStore::open(&dir).unwrap();
    assert!(s2.was_corrupted(), "corruption should be detected");
    // the good prefix is still recovered (supports ForceResendWhenCorruptedStore)
    assert_eq!(s2.get(1, 1).await.unwrap(), vec![(1, b"good".to_vec())]);
    cleanup(&dir);
}

#[tokio::test]
async fn reset_clears_messages_and_seqs() {
    let s = MemoryStore::new();
    s.set_next_sender_seq(10).await.unwrap();
    s.save(3, b"x").await.unwrap();
    s.reset().await.unwrap();
    assert_eq!(s.next_sender_seq().await.unwrap(), 1);
    assert!(s.get(1, 100).await.unwrap().is_empty());
}

#[tokio::test]
async fn factory_builds_each_backend() {
    let dir = unique_dir();
    let configs = [
        StoreConfig::Memory,
        StoreConfig::Noop,
        StoreConfig::File { dir: dir.clone() },
        StoreConfig::CachedFile { dir: dir.clone() },
    ];
    for cfg in configs {
        let s = build_store(&cfg).await.unwrap();
        // every backend implements the trait
        let _ = s.next_sender_seq().await.unwrap();
    }
    cleanup(&dir);
}

#[cfg(feature = "sql")]
#[tokio::test]
async fn sql_store_survives_restart() {
    let dir = unique_dir();
    let url = format!("sqlite:{}/store.db", dir.display());
    {
        let s = truefix_store::SqlStore::connect(&url).await.unwrap();
        s.set_next_sender_seq(8).await.unwrap();
        s.save(3, b"sql-msg").await.unwrap();
    }
    let s2 = truefix_store::SqlStore::connect(&url).await.unwrap();
    assert_eq!(s2.next_sender_seq().await.unwrap(), 8);
    assert_eq!(s2.get(3, 3).await.unwrap(), vec![(3, b"sql-msg".to_vec())]);
    cleanup(&dir);
}

//! T023 — session state-machine transition tests (deterministic, sans-IO).

use truefix_core::{Field, Message};
use truefix_session::{Action, Event, Role, Session, SessionConfig, SessionState};

fn cfg(role: Role) -> SessionConfig {
    let mut c = SessionConfig::new("FIX.4.2", "ME", "YOU", role);
    c.heartbeat_interval = 1;
    c
}

fn inbound(msg_type: &str, seq: i64, hb: Option<i64>, test_req: Option<&str>) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, "FIX.4.2"));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::string(49, "YOU"));
    m.header.set(Field::string(56, "ME"));
    m.header.set(Field::int(34, seq));
    if let Some(h) = hb {
        m.body.set(Field::int(108, h));
    }
    if let Some(t) = test_req {
        m.body.set(Field::string(112, t));
    }
    m
}

fn first_send(actions: &[Action]) -> Option<&Message> {
    actions.iter().find_map(|a| match a {
        Action::Send(m) => Some(m),
        Action::Disconnect => None,
    })
}

#[test]
fn initiator_sends_logon_on_connect() {
    let mut s = Session::new(cfg(Role::Initiator));
    let actions = s.handle(Event::Connected);
    assert_eq!(s.state(), SessionState::AwaitingLogon);
    assert_eq!(first_send(&actions).and_then(Message::msg_type), Some("A"));
}

#[test]
fn acceptor_waits_then_responds_to_logon() {
    let mut s = Session::new(cfg(Role::Acceptor));
    assert!(s.handle(Event::Connected).is_empty());
    assert_eq!(s.state(), SessionState::AwaitingLogon);

    let actions = s.handle(Event::Received(inbound("A", 1, Some(1), None)));
    assert_eq!(s.state(), SessionState::LoggedOn);
    assert_eq!(first_send(&actions).and_then(Message::msg_type), Some("A"));
}

#[test]
fn initiator_becomes_logged_on_when_logon_received() {
    let mut s = Session::new(cfg(Role::Initiator));
    s.handle(Event::Connected);
    let actions = s.handle(Event::Received(inbound("A", 1, Some(1), None)));
    assert_eq!(s.state(), SessionState::LoggedOn);
    assert!(actions.is_empty()); // initiator already sent its logon
}

#[test]
fn test_request_is_answered_with_heartbeat() {
    let mut s = logged_on_acceptor();
    let actions = s.handle(Event::Received(inbound("1", 2, None, Some("ABC"))));
    let reply = first_send(&actions).expect("heartbeat reply");
    assert_eq!(reply.msg_type(), Some("0"));
    assert_eq!(reply.body.get(112).unwrap().as_str().unwrap(), "ABC");
}

#[test]
fn heartbeat_emitted_after_idle_tick() {
    let mut s = logged_on_acceptor();
    let actions = s.handle(Event::Tick); // hb interval = 1
    assert_eq!(first_send(&actions).and_then(Message::msg_type), Some("0"));
}

#[test]
fn start_logout_then_counter_logout_disconnects() {
    let mut s = logged_on_acceptor();
    let actions = s.handle(Event::StartLogout);
    assert_eq!(s.state(), SessionState::AwaitingLogout);
    assert_eq!(first_send(&actions).and_then(Message::msg_type), Some("5"));

    let actions = s.handle(Event::Received(inbound("5", 2, None, None)));
    assert_eq!(s.state(), SessionState::Disconnected);
    assert!(actions.iter().any(|a| matches!(a, Action::Disconnect)));
}

#[test]
fn unsolicited_logout_is_answered_and_disconnects() {
    let mut s = logged_on_acceptor();
    let actions = s.handle(Event::Received(inbound("5", 2, None, None)));
    assert_eq!(s.state(), SessionState::Disconnected);
    assert_eq!(first_send(&actions).and_then(Message::msg_type), Some("5"));
    assert!(actions.iter().any(|a| matches!(a, Action::Disconnect)));
}

#[test]
fn silent_peer_disconnects_after_threshold() {
    let mut s = logged_on_acceptor();
    // hb=1 => disconnect when ticks_since_recv >= 2*1+2 = 4
    let mut disconnected = false;
    for _ in 0..5 {
        if s.handle(Event::Tick)
            .iter()
            .any(|a| matches!(a, Action::Disconnect))
        {
            disconnected = true;
            break;
        }
    }
    assert!(disconnected);
    assert_eq!(s.state(), SessionState::Disconnected);
}

fn logged_on_acceptor() -> Session {
    let mut s = Session::new(cfg(Role::Acceptor));
    s.handle(Event::Connected);
    s.handle(Event::Received(inbound("A", 1, Some(1), None)));
    assert_eq!(s.state(), SessionState::LoggedOn);
    s
}

//! T032–T035 — sequence recovery, resend, SequenceReset, and NextExpectedMsgSeqNum.

use truefix_core::{Field, Message};
use truefix_session::{Action, Event, Role, Session, SessionConfig, SessionState};

fn cfg(role: Role) -> SessionConfig {
    let mut c = SessionConfig::new("FIX.4.4", "ME", "YOU", role);
    c.heartbeat_interval = 30;
    c.reset_on_logon = true;
    c
}

fn msg(msg_type: &str, seq: i64) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, "FIX.4.4"));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::string(49, "YOU"));
    m.header.set(Field::string(56, "ME"));
    m.header.set(Field::int(34, seq));
    m.header.set(Field::string(52, "20240101-00:00:00"));
    m
}

fn with(mut m: Message, tag: u32, value: &str) -> Message {
    m.body.set(Field::string(tag, value));
    m
}

fn with_header(mut m: Message, tag: u32, value: &str) -> Message {
    m.header.set(Field::string(tag, value));
    m
}

fn sends(actions: &[Action]) -> Vec<&Message> {
    actions
        .iter()
        .filter_map(|a| match a {
            Action::Send(m) => Some(m),
            Action::Disconnect => None,
        })
        .collect()
}

fn logged_on_acceptor() -> Session {
    let mut s = Session::new(cfg(Role::Acceptor));
    s.handle(Event::Connected);
    // Logon with ResetSeqNumFlag=Y, seq 1
    let logon = with(msg("A", 1), 108, "30");
    let logon = with(logon, 141, "Y");
    s.handle(Event::Received(logon));
    assert_eq!(s.state(), SessionState::LoggedOn);
    assert_eq!(s.next_in_seq(), 2);
    s
}

#[test]
fn high_seq_triggers_resend_request_and_queues() {
    let mut s = logged_on_acceptor();
    // expected = 2; receive seq 5 -> gap
    let actions = s.handle(Event::Received(msg("0", 5)));
    let out = sends(&actions);
    assert_eq!(out.len(), 1);
    let rr = out[0];
    assert_eq!(rr.msg_type(), Some("2")); // ResendRequest
    assert_eq!(rr.body.get(7).unwrap().as_int().unwrap(), 2); // BeginSeqNo = expected
                                                              // still expecting 2 (the high message is queued, not processed)
    assert_eq!(s.next_in_seq(), 2);
}

#[test]
fn gap_fills_then_queued_message_processed() {
    let mut s = logged_on_acceptor();
    s.handle(Event::Received(msg("0", 5))); // queue 5, request resend from 2
                                            // peer gap-fills 2..5 via SequenceReset-GapFill NewSeqNo=5
    let sr = with(with(msg("4", 2), 123, "Y"), 36, "5");
    s.handle(Event::Received(sr));
    // now expected should have advanced through the queued 5 -> 6
    assert_eq!(s.next_in_seq(), 6);
}

#[test]
fn low_seq_without_possdup_disconnects() {
    let mut s = logged_on_acceptor(); // expected 2
    let actions = s.handle(Event::Received(msg("0", 1))); // too low, no PossDup
    assert_eq!(s.state(), SessionState::Disconnected);
    assert!(actions.iter().any(|a| matches!(a, Action::Disconnect)));
}

#[test]
fn low_seq_with_possdup_is_ignored() {
    let mut s = logged_on_acceptor(); // expected 2
    let dup = with_header(msg("0", 1), 43, "Y"); // PossDupFlag=Y (header field)
    let actions = s.handle(Event::Received(dup));
    assert_eq!(s.state(), SessionState::LoggedOn);
    assert!(actions.is_empty());
    assert_eq!(s.next_in_seq(), 2);
}

#[test]
fn resend_request_resends_app_with_possdup_and_gapfills_admin() {
    // Build an initiator that has sent: logon(1, admin), an app msg(2), a heartbeat(3, admin).
    let mut s = Session::new(cfg(Role::Initiator));
    s.handle(Event::Connected); // logon seq 1 (admin)
    s.send_app(with(msg("D", 0), 55, "AAPL")); // app seq 2 (seq stamped by engine)
                                               // log on so test requests/heartbeats are valid; simulate counter logon
    let logon = with(with(msg("A", 1), 108, "30"), 141, "Y");
    s.handle(Event::Received(logon));

    // Peer asks us to resend 1..3
    let rr = {
        let mut m = msg("2", 2);
        m.body.set(Field::int(7, 1));
        m.body.set(Field::int(16, 3));
        m
    };
    let actions = s.handle(Event::Received(rr));
    let out = sends(&actions);
    // Expect: gap-fill for the admin logon(1), then resent app(2) with PossDup, then gap-fill for 3+
    assert!(
        out.iter().any(|m| m.msg_type() == Some("4")),
        "expected a SequenceReset-GapFill for admin messages"
    );
    let resent_app = out
        .iter()
        .find(|m| m.msg_type() == Some("D"))
        .expect("app message should be resent");
    assert_eq!(resent_app.header.get(43).unwrap().as_str().unwrap(), "Y"); // PossDupFlag
    assert!(resent_app.header.get(122).is_some(), "OrigSendingTime set"); // OrigSendingTime
}

